// Record class (heap, reference type, structural equality)
public record UserDto(int Id, string Name, string Email, DateTimeOffset CreatedAt);

var user1 = new UserDto(1, "Alice", "alice@example.com", now);
var user2 = new UserDto(1, "Alice", "alice@example.com", now);
Console.WriteLine(user1 == user2); // TRUE (structural equality)

// with-expression: immutable update
var updated = user1 with { Email = "newalice@example.com" };

// Record struct (C# 10): stack-allocated
public readonly record struct Coordinate(double Lat, double Lng);

// Nominal record với validation
public record class PaymentResult
{
    public bool Success { get; init; }
    public string? TransactionId { get; init; }
    public string? Error { get; init; }

    public static PaymentResult Ok(string txId) =>
        new() { Success = true, TransactionId = txId };
    public static PaymentResult Fail(string err) =>
        new() { Success = false, Error = err };
}

